export function generateBodyContent(t,n=!1){const{title:e,content:r,items:i}=t;if(!e&&!r)throw new Error("Invalid payload: Title and content are required.");if(n&&(!i||"string"!=typeof i||!i.trim()))throw new Error("Invalid payload: `items` must be a valid non-empty string when hasItems is true.");return n?`<h1>${e}</h1>\n                <p>${r}</p>\n                <div class="table-container">\n                    ${i}\n                </div> `:`\n        <h1>${e}</h1>\n        <p>${r}</p>\n    `}export function injectContentIntoTemplate(t,n,e){return t.replace("{{title}}",n).replace("{{{body}}}",e)}